#!/usr/bin/env bash
# Generated by pivota-spec init-dev-server
# Catalog entry: agent-synthesized: java-spring-direct
# Generator version: init-dev-server@1
#
# Edits ABOVE the END PIVOTA PREAMBLE marker are reset on regen.
# Edits BELOW the marker are preserved on regen.
#
# Why these choices (decision-trace; do not delete):
#   - `set -euo pipefail` not just `-e` — RESEARCH.md Pitfall 4 (silent pipe failures).
#   - `sha256sum` for lockfile hashing — RESEARCH.md "Don't hand-roll" (universal
#     coreutils, no extra dep vs blake3 / git hash-object / md5sum).
#   - Backoff 1s / 2s / 4s — Claude's Discretion per CONTEXT.md (small base, predictable).
#   - Log destination `/tmp/pivota-dev.log` — Open Question #4 resolved (always
#     writable inside Daytona sandboxes; matches existing convention).
#   - Lockfile-sentinel skip combined with INSTALL_PRESENCE_CHECK — RESEARCH.md
#     Pitfall 6 (sentinel survives reboots but install output dirs may not on
#     fresh tmpfs; never skip on a clean directory).
#   - Retry exits with INNER command's last exit code (not a fixed 1) so callers
#     can disambiguate failures from the wrapper.
#   - No mvnw wrapper in backend/ — must use system `mvn` (apt-get installed in pre-exec).
#   - DATABASE_URL normalization: platform may inject mysql:// or raw postgresql:// scheme;
#     convert to jdbc:postgresql:// so HikariCP accepts it (Spring Boot cannot auto-prefix).
#   - SERVER_ADDRESS=0.0.0.0 env preamble: Spring Boot binds server.address from this env
#     var so the preview iframe can reach port 8080 from outside the sandbox loopback.
#   - EXEC_CMD runs 'cd backend &&' because mvn must be invoked from the module directory;
#     -Dspring-boot.run.jvmArguments redundantly passes server.address as a JVM property
#     (belt-and-suspenders alongside the env var).

set -euo pipefail

# === Bash version guard (RESEARCH.md Pitfall 8) ===
# `wait -n` (used by the multi-process variant) requires bash >= 4.3.
# Fail fast with a clear message; do not silently degrade.
if (( BASH_VERSINFO[0] < 4 )) || { (( BASH_VERSINFO[0] == 4 )) && (( BASH_VERSINFO[1] < 3 )); }; then
  echo "[pivota] bash 4.3+ required for 'wait -n'; found ${BASH_VERSION}" >&2
  exit 127
fi

# === D-11.4: tee stdout/stderr to /tmp/pivota-dev.log AND pass through ===
# Researcher resolved log destination: /tmp/pivota-dev.log (always writable,
# matches existing convention). SSE chat panel sees output live AND a file
# exists for scrollback / replay.
mkdir -p /tmp
exec > >(tee -a /tmp/pivota-dev.log) 2>&1
echo "[pivota] $(date -Iseconds) start-dev.sh begin (catalog: agent-synthesized: java-spring-direct)"

# === D-11.1 + D-11.2: per-stack 0.0.0.0 binding + host allowlist relaxation ===
# NOTE: env vars do NOT cover every stack. Vite / webpack-dev-server / Next.js
# allowedHosts require CLI flags or config-file overlays — those live in
# EXEC_CMD or PRE_EXEC_SNIPPET below, not here.
export SERVER_ADDRESS=0.0.0.0

# === D-11.3: .env.example -> .env seed (platform-injection-safe) ===
# Seed .env from .env.example for first boot, but NEVER let an .env.example
# placeholder shadow a variable the platform already injected into the sandbox
# environment. The motivating bug: .env.example shipped a dead
# `DATABASE_URL=postgresql://user:pass@localhost/...` that overrode the injected
# sidecar DATABASE_URL, so Prisma `db push`/`$connect()` failed. Any KEY already
# set in the environment (DATABASE_URL, POSTGRES_*/MYSQL_*, REDIS_URL, PIVOTA_*,
# plus PORT/NODE_ENV from the preamble above) is dropped from the copy so the
# injected value wins. See references/runtime-environment.md §3.
if [[ ! -f .env && -f .env.example ]]; then
  echo "[pivota] seeding .env from .env.example (preserving platform-injected vars)"
  while IFS= read -r line || [[ -n "$line" ]]; do
    trimmed="${line#"${line%%[![:space:]]*}"}"   # left-trim for the test only
    if [[ "$trimmed" == \#* || -z "$trimmed" || "$trimmed" != *"="* ]]; then
      printf '%s\n' "$line"; continue            # keep comments / blanks / non-assignments
    fi
    key="${trimmed#export }"; key="${key%%=*}"; key="${key//[[:space:]]/}"
    if [[ -n "${!key+x}" ]]; then
      printf '# [pivota] %s omitted — provided by platform environment\n' "$key"
    else
      printf '%s\n' "$line"
    fi
  done < .env.example > .env
fi

# === Optional pre-exec snippet (JDK install, rustup, golang one-shot setup) ===
# Catalog entries with PRE_EXEC_SNIPPET inject heavyweight one-time installs
# here. Empty string when not needed.

# === Agent-synthesized pre-exec: install Java 21 + Maven if not present ===
if ! command -v java &>/dev/null || ! java -version 2>&1 | grep -q 'version "21'; then
  echo "[pivota] Java 21 not found — installing via apt-get"
  export DEBIAN_FRONTEND=noninteractive
  apt-get update -qq && apt-get install -y -qq openjdk-21-jdk-headless
  export JAVA_HOME=/usr/lib/jvm/java-21-openjdk-amd64
  export PATH="$JAVA_HOME/bin:$PATH"
fi
if ! command -v mvn &>/dev/null; then
  echo "[pivota] Maven not found — installing via apt-get"
  export DEBIAN_FRONTEND=noninteractive
  apt-get update -qq && apt-get install -y -qq maven
fi

# === DATABASE_URL normalization (platform may inject mysql:// or raw postgresql:// scheme) ===
# Spring Boot / HikariCP requires jdbc:postgresql:// scheme.
# If DATABASE_URL is set but does NOT start with jdbc:postgresql://, construct the correct
# JDBC URL from PGHOST / PGPORT / PGDATABASE / PGUSER / PGPASSWORD, or fall back to the
# application.yml default (jdbc:postgresql://localhost:5432/ureport).
if [[ -n "${DATABASE_URL:-}" && "${DATABASE_URL}" != jdbc:postgresql://* ]]; then
  echo "[pivota] DATABASE_URL scheme is not jdbc:postgresql:// — constructing JDBC URL from PG* vars"
  _PG_HOST="${PGHOST:-localhost}"
  _PG_PORT="${PGPORT:-5432}"
  _PG_DB="${PGDATABASE:-ureport}"
  _PG_USER="${PGUSER:-}"
  _PG_PASS="${PGPASSWORD:-}"
  if [[ -n "$_PG_USER" && -n "$_PG_PASS" ]]; then
    export DATABASE_URL="jdbc:postgresql://${_PG_HOST}:${_PG_PORT}/${_PG_DB}?user=${_PG_USER}&password=${_PG_PASS}"
  elif [[ -n "$_PG_USER" ]]; then
    export DATABASE_URL="jdbc:postgresql://${_PG_HOST}:${_PG_PORT}/${_PG_DB}?user=${_PG_USER}"
  else
    export DATABASE_URL="jdbc:postgresql://${_PG_HOST}:${_PG_PORT}/${_PG_DB}"
  fi
  echo "[pivota] DATABASE_URL normalized to: ${DATABASE_URL%%\?*}?<credentials-redacted>"
fi
# If DATABASE_URL is unset entirely, let application.yml default (jdbc:postgresql://localhost:5432/ureport) apply.

# === D-12: idempotent install via lockfile hash + presence check ===
SENTINEL="/tmp/pivota-setup-sentinel"
LOCK_FILE_PATH="backend/pom.xml"
INSTALL_PRESENCE_CHECK="~/.m2/repository"
INSTALL_CMD='cd backend && mvn dependency:resolve -B -q'   # single-quoted: catalog must escape internal quotes correctly

run_install() {
  echo "[pivota] running install: $INSTALL_CMD"
  bash -c "$INSTALL_CMD"
}

if [[ -n "$LOCK_FILE_PATH" && -f "$LOCK_FILE_PATH" ]]; then
  CURRENT_HASH=$(sha256sum "$LOCK_FILE_PATH" | cut -d' ' -f1)
  PREVIOUS_HASH=$(cat "$SENTINEL" 2>/dev/null || echo "")

  # RESEARCH.md Pitfall 6: lockfile-unchanged is necessary but not sufficient —
  # the install-output directory must also exist (sentinel survives but
  # node_modules / .venv / target might not on a fresh sandbox tmpfs).
  PRESENCE_OK=1
  if [[ -n "$INSTALL_PRESENCE_CHECK" && ! -e "$INSTALL_PRESENCE_CHECK" ]]; then
    PRESENCE_OK=0
  fi

  if [[ "$CURRENT_HASH" == "$PREVIOUS_HASH" && "$PRESENCE_OK" == "1" ]]; then
    echo "[pivota] lockfile unchanged AND install output present; skipping install"
  else
    if [[ "$PRESENCE_OK" == "0" ]]; then
      echo "[pivota] install output ($INSTALL_PRESENCE_CHECK) missing; install required"
    else
      echo "[pivota] lockfile changed (or first boot); install required"
    fi
    run_install
    echo "$CURRENT_HASH" > "$SENTINEL"
  fi
elif [[ -n "$INSTALL_CMD" ]]; then
  # No lockfile to compare; honor any sentinel mismatch by running install once per sandbox.
  if [[ ! -f "$SENTINEL" ]]; then
    run_install
    touch "$SENTINEL"
  fi
fi

# === D-14: retry loop (3 attempts, exponential backoff 1s / 2s / 4s) ===
# Final-attempt exit code propagates the INNER command's exit code, not a
# fixed 1, so the caller (platform / Daytona) can distinguish "wrapper bug"
# from "user command failed with N".
EXEC_CMD='cd backend && mvn spring-boot:run -Dspring-boot.run.jvmArguments="-Dserver.address=0.0.0.0"'
ATTEMPT=1
DELAY=1
while (( ATTEMPT <= 3 )); do
  echo "[pivota] attempt $ATTEMPT: $EXEC_CMD"
  if bash -c "$EXEC_CMD"; then
    echo "[pivota] inner command exited 0; propagating success"
    exit 0
  fi
  EXIT_CODE=$?
  if (( ATTEMPT == 3 )); then
    echo "[pivota] all 3 attempts failed (last exit=$EXIT_CODE); surfacing failure"
    exit "$EXIT_CODE"
  fi
  echo "[pivota] attempt $ATTEMPT failed (exit=$EXIT_CODE); retrying in ${DELAY}s"
  sleep "$DELAY"
  DELAY=$(( DELAY * 2 ))
  ATTEMPT=$(( ATTEMPT + 1 ))
done

# Unreachable, but keep for analyzer happiness
exit 1
